// Read topics from Minio, fall back to hardcoded list
let topics = [];
try {
  const raw = $('Read Topics from Minio').item.json.Body;
  topics = JSON.parse(raw || '[]');
} catch(e) { topics = []; }

// Fallback topics if Minio empty
if (topics.length === 0) {
  topics = ["AI-native company building playbook", "12-week product experiment framework", "remote-first team culture 2026", "bootstrapping vs venture funding decision", "building in public strategy", "personal brand for founders", "async-first communication systems", "solo founder mental health practices", "product-led growth for small teams", "side project to profitable product", "AI tools for indie hackers", "digital nomad infrastructure setup", "building audience before product", "micro-SaaS niche validation", "founder-led sales tactics"];
}

// Pick random topic
const topic = topics[Math.floor(Math.random() * topics.length)];
return [{ json: { topic } }];

const topic = $json.topic;
const slug = $json.slug;
const date = $json.date;
const rssContext = $json.rssContext || '';

const systemPrompt = "You are a writer for The Unnamed Roads (theunnamedroads.com) \u2014 a publication about the unconventional path: building companies, experiments, and adventures without a map. Write in a thoughtful, direct, slightly poetic tone. The audience is indie hackers, founders, and curious builders.";

const rssBlock = rssContext ? rssContext + '\n\nUse the above context to make your article timely and grounded in current industry developments. Reference or expand on relevant trends where appropriate.\n\n' : '';

const userPrompt = "Write a comprehensive, well-structured article about: __TOPIC__\n\n".replace('__TOPIC__', topic)
  + rssBlock
  + "Requirements:\n- 1200-1800 words\n- Practical and honest, avoid hype\n- Include real examples and actionable insights\n- Use H2 and H3 headers for structure\n- End with key takeaways\n- NO frontmatter, just the article body starting with a compelling intro paragraph";

return {
  systemPrompt,
  userPrompt,
  slug,
  topic,
  date
};

const body = $input.item.json;
const slug = $('Pick Topic').item.json.slug;
const topic = $('Pick Topic').item.json.topic;
const date = $('Pick Topic').item.json.date;
const articleText = body.choices?.[0]?.message?.content || '';
let title = topic.split(' ').map(w=>w[0].toUpperCase()+w.slice(1)).join(' ');
let bodyText = articleText;
const firstLine = articleText.split('
')[0];
if (firstLine.startsWith('# ')) { title = firstLine.slice(2).trim(); bodyText = articleText.split('
').slice(1).join('
').trim(); }
const firstPara = bodyText.replace(/^#+.*$/gm,'').replace(/
+/g,' ').trim().slice(0,200).split('.').slice(0,2).join('.')+'.'; 
const description = firstPara.slice(0,160);
const tags = topic.toLowerCase().split(' ').filter(w=>w.length>3).slice(0,4);
const frontmatter = `---
title: "${title.replace(/"/g, "'")}"
description: "${description.replace(/"/g, "'")}"
publishedDate: ${date}
dateModified: ${date}
author: "The Unnamed Roads"
authorUrl: "https://theunnamedroads.com"
disclosure: "AI-assisted content"
tags: [${tags.map(t=>`'${t}'`).join(', ')}]
draft: false
---`;
const fullContent = frontmatter + '

' + bodyText;
return [{ json: { fullContent, title, slug } }];

// Append published slug to used-slugs list in workflow static data
const slug = $('Format Article').item.json.slug || $json.slug || '';
if (slug) {
  const data = $getWorkflowStaticData('global');
  if (!data.usedSlugs) data.usedSlugs = [];
  if (!data.usedSlugs.includes(slug)) {
    data.usedSlugs.push(slug);
  }
  // Keep max 500 slugs
  if (data.usedSlugs.length > 500) {
    data.usedSlugs = data.usedSlugs.slice(-500);
  }
}
return $input.all();

// Parse RSS XML from both feeds and extract top headlines
function parseRSS(xml, maxItems) {
  if (!xml || typeof xml !== 'string') return [];
  const items = [];
  const matches = xml.match(/<item[\s>][\s\S]*?<\/item>/gi) || 
                  xml.match(/<entry[\s>][\s\S]*?<\/entry>/gi) || [];
  for (const item of matches.slice(0, maxItems)) {
    const titleMatch = item.match(/<title[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/i);
    const descMatch = item.match(/<description[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/description>/i) ||
                      item.match(/<summary[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/summary>/i);
    const title = (titleMatch?.[1] || '').replace(/<[^>]+>/g, '').trim();
    const desc = (descMatch?.[1] || '').replace(/<[^>]+>/g, '').replace(/\s+/g,' ').trim().substring(0, 150);
    if (title.length > 10) items.push(title + (desc ? ': ' + desc : ''));
  }
  return items;
}

// Get XML from both previous nodes
let xml1 = '', xml2 = '';
try { xml1 = String($('Fetch RSS 1').item.json.data || $('Fetch RSS 1').item.json.body || ''); } catch(e) {}
try { xml2 = String($('Fetch RSS 2').item.json.data || $('Fetch RSS 2').item.json.body || ''); } catch(e) {}

const headlines1 = parseRSS(xml1, 4);
const headlines2 = parseRSS(xml2, 3);
const allHeadlines = [...headlines1, ...headlines2].slice(0, 6);

const contextText = allHeadlines.length > 0
  ? 'CURRENT INDUSTRY CONTEXT (recent headlines):\n' + allHeadlines.map(h => '\u2022 ' + h).join('\n')
  : '';

// Pass through topic + add rssContext
return {
  topic: $('Pick Topic').item.json.topic,
  slug: $('Pick Topic').item.json.slug,
  date: $('Pick Topic').item.json.date,
  rssContext: contextText,
  rssCount: allHeadlines.length
};

